fn validate_dir_name(name: &str) -> Result<()> {
    if name.is_empty()
        || name.contains('/')
        || name.contains('\\')
        || name.contains('\0')
        || name == "."
        || name == ".."
    {
        anyhow::bail!(
            "Invalid name '{}': must not be empty, contain path separators, or be '.' or '..'",
            name
        );
    }
    Ok(())
}
